INSERT INTO IFSAL21R
(
	  COMPKEY
	, IFSALSQ
	, plant
	, line
	, itemcate
	, palletNo
	, createDateTime
	, printDateTime
	, seq
	, alc
	, carType
	, goodsCode
	, goodsName
	, bodyNo
	, receiveDateTime
	, checkDateTime
	, IFRCVUR
)
VALUES
(
	  #{compkey}
	, #{ifsalsq}
	, #{plant}
	, #{line}
	, #{itemcate}
	, #{palletNo}
	, #{createDateTime}
	, #{printDateTime}
	, #{seq}
	, #{alc}
	, #{carType}
	, 


			CONCAT((SELECT SAATC05 FROM OCODMA WHERE COMPKEY = #{compkey} AND CARTYPE = #{carType}), '-', #{goodsCode})


			'ZZZ-ZZZZZ-ZZZZZ'


	, #{goodsName}
	, #{bodyNo}
	, #{receiveDateTime}
	, #{checkDateTime}
	, #{ifrcvur}
)
ON DUPLICATE KEY UPDATE
  alc = #{alc}
, goodsCode =  


			CONCAT((SELECT SAATC05 FROM OCODMA WHERE COMPKEY = #{compkey} AND CARTYPE = #{carType}), '-', #{goodsCode})


			'ZZZ-ZZZZZ-ZZZZZ'


, palletNo = #{palletNo}
, printDateTime = #{printDateTime}
, checkDateTime = #{checkDateTime}
, UPDTCHK = UPDTCHK + 1

